params.cmd:
cat > {{voice_action_json}} <<'EOF'
{"action":"generate_voice","request_id":"trial-narrated-report-audio","text":"{{report_summary}}","profile_ref":{"profile_id":"{{profile_id}}"},"engine":{"engine_id":"local_say"},"rendering":{"language":"ja","chunking":{"max_chunk_chars":4000,"crossfade_ms":50,"preserve_paralinguistic_tags":true}},"delivery":{"mode":"artifact","format":"aiff","artifact_path":"{{audio_path}}","emit_progress_packets":true},"routing":{"personal_voice_mode":"allow_fallback"}}
EOF
cat > {{video_action_json}} <<'EOF'
{"action":"create_narrated_intro_movie","params":{"narrated_video_brief":{"kind":"narrated-video-brief","version":"1.0.0","intent":"executive-summary","title":"Kyberion Monthly Strategic Update","script":{"hook":"Greetings.","feature":"{{report_summary}}","cta":"Details in full report."},"narration":{"artifact_ref":"{{audio_path}}"},"design_system":{"brand_name":"Kyberion Sovereign","theme_tokens":{"background_color":"#000000"}},"output":{"format":"mp4","target_path":"{{video_output_path}}","await_completion":true}}}}
EOF
cat > {{video_render_policy_json}} <<'EOF'
{"version":"1.0.0","queue":{"concurrency":1,"cancellation":"queued_or_running"},"progress":{"throttle_ms":250,"min_percent_delta":2,"emit_heartbeat":true},"bundle":{"default_bundle_root":"active/shared/tmp/video-composition","copy_declared_assets":false},"render":{"allowed_output_formats":["mp4","mov","webm"],"enable_backend_rendering":true,"backend":"hyperframes_cli","quality":"standard","command_timeout_ms":300000}}
EOF
